Below is a complete FastAPI implementation for `POST /api/upload`.

```python
import asyncio
import errno
import hashlib
import json
import logging
import os
import re
import shutil
import time
import unicodedata
import uuid
import warnings
from pathlib import Path
from typing import Optional

from fastapi import FastAPI, File, Request, UploadFile
from fastapi.exceptions import RequestValidationError
from fastapi.responses import JSONResponse
from PIL import Image, UnidentifiedImageError
from starlette.requests import ClientDisconnect

app = FastAPI()

MAX_FILE_SIZE = 10 * 1024 * 1024
MAX_REQUEST_SIZE = MAX_FILE_SIZE + 1024 * 1024  # allow multipart overhead
CHUNK_SIZE = 64 * 1024
MAGIC_BYTES_TO_KEEP = 64
MAX_CONCURRENT_UPLOADS = 16
MIN_FREE_SPACE_AFTER_UPLOAD = 50 * 1024 * 1024
MAX_IMAGE_PIXELS = 40_000_000
UPLOAD_DIR = Path("./uploads").resolve()

upload_slots = asyncio.Semaphore(MAX_CONCURRENT_UPLOADS)

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger("uploads")

Image.MAX_IMAGE_PIXELS = MAX_IMAGE_PIXELS

ALLOWED_TYPES = {
    "jpeg": {
        "ext": ".jpg",
        "mime": {"image/jpeg", "image/pjpeg"},
        "pil": "JPEG",
    },
    "png": {
        "ext": ".png",
        "mime": {"image/png", "image/x-png"},
        "pil": "PNG",
    },
    "gif": {
        "ext": ".gif",
        "mime": {"image/gif"},
        "pil": "GIF",
    },
    "webp": {
        "ext": ".webp",
        "mime": {"image/webp"},
        "pil": "WEBP",
    },
}

GENERIC_MIME = {"application/octet-stream", "binary/octet-stream"}


class UploadProblem(Exception):
    def __init__(self, status_code: int, code: str, message: str, details: Optional[dict] = None):
        self.status_code = status_code
        self.code = code
        self.message = message
        self.details = details or {}


def json_error(status_code: int, code: str, message: str, request_id: str, details: Optional[dict] = None):
    return JSONResponse(
        status_code=status_code,
        content={
            "ok": False,
            "request_id": request_id,
            "error": {
                "code": code,
                "message": message,
                "details": details or {},
            },
        },
    )


def log_event(event: str, **fields):
    logger.info(json.dumps({"event": event, **fields}, default=str))


def normalize_content_type(value: Optional[str]) -> Optional[str]:
    if not value:
        return None
    return value.split(";", 1)[0].strip().lower()


def detect_image_type(sample: bytes) -> Optional[str]:
    # Magic-byte validation prevents trusting spoofable Content-Type headers or extensions.
    if sample.startswith(b"\xff\xd8\xff"):
        return "jpeg"
    if sample.startswith(b"\x89PNG\r\n\x1a\n"):
        return "png"
    if sample.startswith((b"GIF87a", b"GIF89a")):
        return "gif"
    if len(sample) >= 12 and sample[:4] == b"RIFF" and sample[8:12] == b"WEBP":
        return "webp"
    return None


def validate_declared_mime(declared: Optional[str], detected: str):
    # Header is not trusted, but contradictory/unsupported headers are rejected.
    if declared is None or declared in GENERIC_MIME:
        return

    allowed_mimes = set().union(*(v["mime"] for v in ALLOWED_TYPES.values()))
    if declared not in allowed_mimes:
        raise UploadProblem(
            415,
            "unsupported_declared_content_type",
            "Declared Content-Type is not an allowed image type.",
            {"declared_content_type": declared},
        )

    if declared not in ALLOWED_TYPES[detected]["mime"]:
        raise UploadProblem(
            415,
            "mime_mismatch",
            "Declared Content-Type does not match the uploaded file content.",
            {"declared_content_type": declared, "detected_type": detected},
        )


def sanitize_filename(filename: str) -> str:
    # Handles path traversal, Windows paths, control chars, Unicode confusables,
    # reserved device names, hidden names, and filesystem length limits.
    if "\x00" in filename:
        raise UploadProblem(400, "invalid_filename", "Filename contains a NUL byte.")

    if len(filename.encode("utf-8", "ignore")) > 255:
        raise UploadProblem(400, "filename_too_long", "Filename is too long.")

    filename = filename.replace("\\", "/").rsplit("/", 1)[-1]
    filename = unicodedata.normalize("NFKC", filename)

    stem = Path(filename).stem
    stem = re.sub(r"[\x00-\x1f\x7f]", "", stem)
    stem = re.sub(r"\s+", "-", stem)
    stem = re.sub(r"[^A-Za-z0-9._-]", "-", stem)
    stem = re.sub(r"-{2,}", "-", stem)
    stem = stem.strip("._-")

    if not stem:
        stem = "upload"

    reserved = {
        "CON", "PRN", "AUX", "NUL",
        *(f"COM{i}" for i in range(1, 10)),
        *(f"LPT{i}" for i in range(1, 10)),
    }
    if stem.upper() in reserved:
        stem = f"file-{stem}"

    return stem[:100].rstrip("._-") or "upload"


def ensure_upload_dir():
    # Storage misconfiguration: missing directory, symlinked directory, or bad permissions.
    UPLOAD_DIR.mkdir(parents=True, exist_ok=True)

    if not UPLOAD_DIR.is_dir():
        raise UploadProblem(500, "storage_not_directory", "Upload path is not a directory.")

    if UPLOAD_DIR.is_symlink():
        raise UploadProblem(500, "storage_symlink_rejected", "Upload directory must not be a symlink.")

    free = shutil.disk_usage(UPLOAD_DIR).free
    if free < MAX_FILE_SIZE + MIN_FREE_SPACE_AFTER_UPLOAD:
        raise UploadProblem(
            500,
            "storage_insufficient_space",
            "Not enough free disk space to safely accept uploads.",
            {"free_bytes": free},
        )


def create_temp_file():
    # O_EXCL and random names avoid races between concurrent uploads.
    flags = os.O_WRONLY | os.O_CREAT | os.O_EXCL
    if hasattr(os, "O_NOFOLLOW"):
        flags |= os.O_NOFOLLOW

    for _ in range(10):
        temp_path = UPLOAD_DIR / f".upload-{uuid.uuid4().hex}.tmp"
        try:
            fd = os.open(temp_path, flags, 0o600)
            return fd, temp_path
        except FileExistsError:
            continue

    raise UploadProblem(500, "tempfile_create_failed", "Could not create a unique temporary file.")


def write_all(fd: int, data: bytes):
    # Handles partial writes and EINTR explicitly.
    view = memoryview(data)
    while view:
        try:
            written = os.write(fd, view)
        except InterruptedError:
            continue

        if written == 0:
            raise OSError(errno.EIO, "zero-byte write")

        view = view[written:]


def fsync_directory(path: Path):
    # Ensures rename durability on filesystems that require directory fsync.
    if not hasattr(os, "O_DIRECTORY"):
        return

    dir_fd = os.open(path, os.O_DIRECTORY)
    try:
        os.fsync(dir_fd)
    finally:
        os.close(dir_fd)


def cleanup_temp(path: Optional[Path]):
    if path and path.exists():
        try:
            path.unlink()
        except OSError:
            logger.exception("failed to remove temporary upload file")


def map_storage_error(exc: OSError) -> UploadProblem:
    if exc.errno in {errno.ENOSPC, getattr(errno, "EDQUOT", errno.ENOSPC)}:
        return UploadProblem(500, "storage_insufficient_space", "Disk space or quota exhausted during upload.")
    if exc.errno in {errno.EACCES, errno.EPERM}:
        return UploadProblem(500, "storage_permission_denied", "Server cannot write to upload storage.")
    if exc.errno == errno.EIO:
        return UploadProblem(500, "storage_io_error", "Storage I/O error while saving upload.")
    return UploadProblem(500, "storage_error", "Could not save uploaded file.", {"errno": exc.errno})


def validate_container_trailer(kind: str, magic: bytes, tail: bytes, size: int):
    # Catches common truncation and trailing-garbage cases before finalizing.
    if kind == "jpeg" and not tail.endswith(b"\xff\xd9"):
        raise UploadProblem(415, "malformed_jpeg", "JPEG is missing its end marker.")

    if kind == "png" and not tail.endswith(b"\x00\x00\x00\x00IEND\xaeB`\x82"):
        raise UploadProblem(415, "malformed_png", "PNG is missing its IEND trailer.")

    if kind == "gif" and not tail.endswith(b";"):
        raise UploadProblem(415, "malformed_gif", "GIF is missing its trailer byte.")

    if kind == "webp" and len(magic) >= 12:
        riff_size = int.from_bytes(magic[4:8], "little") + 8
        if riff_size != size:
            raise UploadProblem(415, "malformed_webp", "WebP RIFF size does not match file size.")


def verify_image_with_pillow(path: Path, detected: str) -> dict:
    # Detects corrupt images, decompression bombs, and magic/Pillow format mismatches.
    try:
        with warnings.catch_warnings():
            warnings.simplefilter("error", Image.DecompressionBombWarning)

            with Image.open(path) as img:
                if img.format != ALLOWED_TYPES[detected]["pil"]:
                    raise UploadProblem(
                        415,
                        "image_format_mismatch",
                        "Image decoder format does not match magic bytes.",
                        {"magic_type": detected, "decoder_format": img.format},
                    )

                width, height = img.size
                if width <= 0 or height <= 0:
                    raise UploadProblem(415, "invalid_dimensions", "Image has invalid dimensions.")

                if width * height > MAX_IMAGE_PIXELS:
                    raise UploadProblem(
                        413,
                        "image_pixel_limit_exceeded",
                        "Image dimensions are too large.",
                        {"width": width, "height": height, "max_pixels": MAX_IMAGE_PIXELS},
                    )

                img.verify()

        return {"width": width, "height": height}

    except UploadProblem:
        raise
    except Image.DecompressionBombError:
        raise UploadProblem(413, "image_pixel_limit_exceeded", "Image exceeds safe pixel limits.")
    except Image.DecompressionBombWarning:
        raise UploadProblem(413, "image_pixel_limit_exceeded", "Image exceeds safe pixel limits.")
    except UnidentifiedImageError:
        raise UploadProblem(415, "invalid_image", "Uploaded file is not a valid image.")
    except OSError:
        raise UploadProblem(415, "invalid_image", "Uploaded image is corrupt or truncated.")


@app.on_event("startup")
def startup():
    ensure_upload_dir()

    # Reliability: remove abandoned temp files from crashed/restarted uploads.
    cutoff = time.time() - 24 * 60 * 60
    for path in UPLOAD_DIR.glob(".upload-*.tmp"):
        try:
            if path.is_file() and path.stat().st_mtime < cutoff:
                path.unlink()
                log_event("stale_temp_removed", path=str(path))
        except OSError:
            logger.exception("failed stale temp cleanup")


@app.middleware("http")
async def upload_content_length_guard(request: Request, call_next):
    if request.method == "POST" and request.url.path == "/api/upload":
        request_id = request.headers.get("x-request-id", uuid.uuid4().hex)
        raw_length = request.headers.get("content-length")

        if raw_length is not None:
            try:
                content_length = int(raw_length)
            except ValueError:
                log_event("upload_failed", request_id=request_id, status=400, code="invalid_content_length")
                return json_error(400, "invalid_content_length", "Invalid Content-Length header.", request_id)

            if content_length > MAX_REQUEST_SIZE:
                log_event("upload_failed", request_id=request_id, status=413, code="request_too_large")
                return json_error(413, "request_too_large", "Upload request is too large.", request_id)

    return await call_next(request)


@app.exception_handler(RequestValidationError)
async def validation_handler(request: Request, exc: RequestValidationError):
    request_id = request.headers.get("x-request-id", uuid.uuid4().hex)
    log_event("upload_failed", request_id=request_id, status=400, code="invalid_request")
    return json_error(400, "invalid_request", "Request must include multipart field 'file'.", request_id)


@app.exception_handler(ClientDisconnect)
async def disconnect_handler(request: Request, exc: ClientDisconnect):
    request_id = request.headers.get("x-request-id", uuid.uuid4().hex)
    log_event("upload_failed", request_id=request_id, status=400, code="client_disconnected")
    return json_error(400, "client_disconnected", "Client disconnected during upload.", request_id)


@app.post("/api/upload")
async def upload_image(request: Request, file: UploadFile = File(...)):
    request_id = request.headers.get("x-request-id", uuid.uuid4().hex)
    client_ip = request.client.host if request.client else None
    started = time.monotonic()

    temp_path = None
    fd = None
    acquired = False

    original_filename = file.filename or ""
    declared_type = normalize_content_type(file.content_type)

    log_event(
        "upload_started",
        request_id=request_id,
        client_ip=client_ip,
        filename=original_filename[:255],
        declared_content_type=declared_type,
    )

    try:
        try:
            await asyncio.wait_for(upload_slots.acquire(), timeout=1.0)
            acquired = True
        except asyncio.TimeoutError:
            raise UploadProblem(503, "server_busy", "Too many uploads are in progress. Try again later.")

        if not original_filename:
            raise UploadProblem(400, "missing_filename", "Uploaded file must have a filename.")

        if declared_type and declared_type not in GENERIC_MIME:
            all_allowed = set().union(*(v["mime"] for v in ALLOWED_TYPES.values()))
            if declared_type not in all_allowed:
                raise UploadProblem(
                    415,
                    "unsupported_declared_content_type",
                    "Declared Content-Type is not an allowed image type.",
                    {"declared_content_type": declared_type},
                )

        safe_stem = sanitize_filename(original_filename)
        ensure_upload_dir()

        fd, temp_path = create_temp_file()

        size = 0
        sha256 = hashlib.sha256()
        magic = bytearray()
        tail = b""
        detected_type = None

        while True:
            if await request.is_disconnected():
                raise UploadProblem(400, "client_disconnected", "Client disconnected during upload.")

            chunk = await asyncio.wait_for(file.read(CHUNK_SIZE), timeout=30)
            if not chunk:
                break

            size += len(chunk)

            # Size limit enforced while streaming, including chunked requests without Content-Length.
            if size > MAX_FILE_SIZE:
                raise UploadProblem(
                    413,
                    "file_too_large",
                    "Uploaded file exceeds the 10MB limit.",
                    {"max_bytes": MAX_FILE_SIZE},
                )

            if len(magic) < MAGIC_BYTES_TO_KEEP:
                magic.extend(chunk[: MAGIC_BYTES_TO_KEEP - len(magic)])

            tail = (tail + chunk)[-32:]

            if detected_type is None and len(magic) >= 12:
                detected_type = detect_image_type(bytes(magic))
                if detected_type is None:
                    raise UploadProblem(
                        415,
                        "unsupported_media_type",
                        "Only JPEG, PNG, GIF, and WebP images are allowed.",
                    )

            sha256.update(chunk)
            write_all(fd, chunk)

        if size == 0:
            raise UploadProblem(400, "empty_file", "Uploaded file is empty.")

        detected_type = detect_image_type(bytes(magic))
        if detected_type is None:
            raise UploadProblem(415, "unsupported_media_type", "Only JPEG, PNG, GIF, and WebP images are allowed.")

        validate_declared_mime(declared_type, detected_type)
        validate_container_trailer(detected_type, bytes(magic), tail, size)

        # Flush before validation and rename so a successful response means durable storage.
        os.fsync(fd)
        os.close(fd)
        fd = None

        image_info = verify_image_with_pillow(temp_path, detected_type)

        upload_id = uuid.uuid4().hex
        stored_filename = f"{safe_stem}-{upload_id}{ALLOWED_TYPES[detected_type]['ext']}"
        final_path = (UPLOAD_DIR / stored_filename).resolve()

        # Defense-in-depth against path traversal after filename processing.
        final_path.relative_to(UPLOAD_DIR)

        # Atomic write pattern: temp file in same directory, then atomic rename.
        os.replace(temp_path, final_path)
        temp_path = None
        fsync_directory(UPLOAD_DIR)

        duration_ms = round((time.monotonic() - started) * 1000, 2)

        log_event(
            "upload_succeeded",
            request_id=request_id,
            status=201,
            client_ip=client_ip,
            stored_filename=stored_filename,
            size=size,
            detected_type=detected_type,
            sha256=sha256.hexdigest(),
            duration_ms=duration_ms,
        )

        return JSONResponse(
            status_code=201,
            content={
                "ok": True,
                "request_id": request_id,
                "file": {
                    "id": upload_id,
                    "filename": stored_filename,
                    "size": size,
                    "content_type": next(iter(ALLOWED_TYPES[detected_type]["mime"])),
                    "sha256": sha256.hexdigest(),
                    **image_info,
                },
            },
        )

    except UploadProblem as exc:
        cleanup_temp(temp_path)

        log_event(
            "upload_failed",
            request_id=request_id,
            status=exc.status_code,
            code=exc.code,
            client_ip=client_ip,
            duration_ms=round((time.monotonic() - started) * 1000, 2),
        )

        return json_error(exc.status_code, exc.code, exc.message, request_id, exc.details)

    except OSError as exc:
        cleanup_temp(temp_path)
        mapped = map_storage_error(exc)

        log_event(
            "upload_failed",
            request_id=request_id,
            status=500,
            code=mapped.code,
            client_ip=client_ip,
        )

        return json_error(500, mapped.code, mapped.message, request_id, mapped.details)

    except asyncio.CancelledError:
        cleanup_temp(temp_path)
        log_event("upload_cancelled", request_id=request_id, client_ip=client_ip)
        raise

    except Exception:
        cleanup_temp(temp_path)
        logger.exception("unexpected upload failure", extra={"request_id": request_id})
        return json_error(500, "internal_error", "Unexpected server error while processing upload.", request_id)

    finally:
        if fd is not None:
            try:
                os.close(fd)
            except OSError:
                pass

        if acquired:
            upload_slots.release()

        await file.close()
